import React, { useEffect, useState, useCallback } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";

/* ================= DRAG & DROP ================= */
import {
  DndContext,
  closestCenter,
} from "@dnd-kit/core";

import {
  arrayMove,
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";

import { CSS } from "@dnd-kit/utilities";

/* ================= SORTABLE CARD ================= */
function TaskCard({ task, ...props }) {
  const { attributes, listeners, setNodeRef, transform, transition } =
    useSortable({ id: task.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`p-6 rounded-2xl shadow-lg border
        ${task.completed ? "bg-gray-200" : "bg-white"}
        ${task.isOverdue ? "ring-2 ring-red-500 animate-pulse" : ""}
      `}
    >
      {/* DRAG HANDLE */}
      <div {...attributes} {...listeners} className="cursor-grab text-gray-400 mb-2">
        ☰ Drag
      </div>

      <div className="flex justify-between">
        <div>
          <h3 className="font-bold">{task.title}</h3>
          <p className="text-sm text-gray-500">
            {task.priority} • {task.category}
          </p>
          <p className="text-xs text-gray-400">{task.dueDate}</p>
        </div>

        {/* ACTIONS */}
        <div className="flex flex-col items-end gap-2">

          {/* COMPLETE */}
          {!task.completed && (
            <button
              onClick={() => props.completeTask(task.id)}
              className="text-green-600"
            >
              ✓ Complete
            </button>
          )}

          {/* DELETE */}
          <button
            onClick={() => props.setDeleteId(task.id)}
            className="text-red-500"
          >
            ✕ Delete
          </button>

          {/* EDIT (BELOW COMPLETE & DELETE) */}
          <button
            disabled={task.completed}
            onClick={() => props.setEditTask(task)}
            className={`text-blue-500 ${task.completed ? "opacity-30 cursor-not-allowed" : ""}`}
          >
            ✎ Edit
          </button>

          {/* AI FIX */}
          {!task.completed && (
            <button
              onClick={() => props.autoFix(task)}
              className="text-purple-600 text-xs"
            >
              🤖 Auto Fix
            </button>
          )}
        </div>
      </div>

      {task.completed && (
        <p className="text-green-600 mt-3">Completed ✅</p>
      )}
    </div>
  );
}

/* ================= MAIN COMPONENT ================= */
export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [deleteId, setDeleteId] = useState(null);

  const [showModal, setShowModal] = useState(false);
  const [editTask, setEditTask] = useState(null);

  const [filterPriority, setFilterPriority] = useState("");
  const [filterCategory, setFilterCategory] = useState("");

  /* ================= FETCH ================= */
  const fetchAll = useCallback(async () => {
    const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
    const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());

    setTasks(
      (t || []).map(task => ({
        ...task,
        isOverdue:
          task.dueDate &&
          !task.completed &&
          new Date(task.dueDate) < new Date(),
      }))
    );

    setNotifications(n || []);
  }, []);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  /* ================= COMPLETE ================= */
  const completeTask = async (id) => {
    await fetch(`http://localhost:8086/tasks/${id}/complete`, {
      method: "PUT",
    });

    setTasks(prev =>
      prev.map(t => (t.id === id ? { ...t, completed: true } : t))
    );
  };

  /* ================= DELETE ================= */
  const deleteTask = async () => {
    await fetch(`http://localhost:8086/tasks/${deleteId}`, {
      method: "DELETE",
    });

    setTasks(prev => prev.filter(t => t.id !== deleteId));
    setDeleteId(null);
  };

  /* ================= AI AUTO FIX ================= */
  const autoFix = (task) => {
    const fixed = {
      ...task,
      title: "FIXED: " + task.title,
      priority: task.priority === "LOW" ? "MEDIUM" : task.priority,
      category: task.category || "GENERAL",
    };

    setTasks(prev =>
      prev.map(t => (t.id === task.id ? fixed : t))
    );
  };

  /* ================= DRAG END ================= */
  const handleDragEnd = (event) => {
    const { active, over } = event;

    if (active.id !== over.id) {
      setTasks((items) => {
        const oldIndex = items.findIndex(i => i.id === active.id);
        const newIndex = items.findIndex(i => i.id === over.id);
        return arrayMove(items, oldIndex, newIndex);
      });
    }
  };

  /* ================= FILTER ================= */
  const filteredTasks = tasks.filter(t => {
    return (
      (filterPriority ? t.priority === filterPriority : true) &&
      (filterCategory ? t.category === filterCategory : true)
    );
  });

  /* ================= UI ================= */
  return (
    <div className="min-h-screen p-6 bg-gradient-to-br from-indigo-100 to-purple-200">

      <Dashboard />

      {/* FILTERS */}
      <div className="flex gap-3 mb-4">
        <select onChange={(e) => setFilterPriority(e.target.value)}>
          <option value="">All Priority</option>
          <option>LOW</option>
          <option>MEDIUM</option>
          <option>HIGH</option>
        </select>

        <input
          placeholder="Category filter"
          onChange={(e) => setFilterCategory(e.target.value)}
          className="border p-2"
        />
      </div>

      {/* ADD BUTTON */}
      <button
        onClick={() => setShowModal(true)}
        className="bg-purple-500 text-white px-4 py-2 rounded mb-4"
      >
        + Add Task
      </button>

      {/* DRAG & DROP AREA */}
      <DndContext collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <SortableContext items={filteredTasks} strategy={verticalListSortingStrategy}>
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">

            {filteredTasks.map(task => (
              <TaskCard
                key={task.id}
                task={task}
                completeTask={completeTask}
                setDeleteId={setDeleteId}
                setEditTask={(t) => {
                  setEditTask(t);
                  setShowModal(true);
                }}
                autoFix={autoFix}
              />
            ))}

          </div>
        </SortableContext>
      </DndContext>

      {/* MODAL */}
      {showModal && (
        <AddTask
          closeModal={() => {
            setShowModal(false);
            setEditTask(null);
          }}
          editTask={editTask}
          isEdit={!!editTask}
          onTaskAdded={(t) => {
            setTasks(prev => {
              const exists = prev.find(x => x.id === t.id);
              return exists
                ? prev.map(x => (x.id === t.id ? t : x))
                : [...prev, t];
            });
            setShowModal(false);
            setEditTask(null);
          }}
        />
      )}

      {/* DELETE */}
      {deleteId && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <p>Delete task?</p>
            <button onClick={deleteTask}>Yes</button>
            <button onClick={() => setDeleteId(null)}>No</button>
          </div>
        </div>
      )}

      {/* NOTIFICATIONS */}
      <div className="mt-6">
        {notifications.map(n => (
          <div key={n.id} className="bg-white p-2 mb-2 shadow">
            {n.message}
          </div>
        ))}
      </div>
    </div>
  );
}
